"""
MKT Original Language Commentary — 2 Chronicles chapters 32–34
Run: python3 scripts/zc-original-2chronicles-32-34.py

Ch32: Sennacherib's invasion and Hezekiah's response
      bāśār vs. divine arm (32:8); yᵉhûdît = Judean language (32:18);
      wayyigbah libbô = pride-idiom (32:25); kānaʿ = Hezekiah's humbling (32:26);
      Siloam tunnel (32:30); Babylonian envoys as divine test (32:31)
Ch33: Manasseh's apostasy and exile-restoration (unique to Chronicles)
      ṣĕḇāʾ haššāmayim = host of heaven; ḥôḥîm = hooks for captives;
      kānaʿ restoration formula (33:12); wayyēḏaʿ kî YHWH hûʾ hāʾĕlōhîm (33:13);
      Amon's ʿam hāʾāreṣ dynamic (33:25)
Ch34: Josiah's progressive reform (eighth/twelfth/eighteenth year structure);
      maṣāʾ sēper hattôrāh (34:14); qāraʿ bĕgādîm = garment-tearing (34:19);
      Huldah the prophetess in the Mishneh (34:22); kānaʿ again (34:27);
      wayyaʿmod ʿal-ʿammûḏô (34:31); kārat bĕrît covenant formula (34:31)

Key decisions:
- hayyāh šōmēr (33:10): "paid no attention" rather than "did not listen" to capture the active ignoring
- tôrat YHWH (34:14): "Torah of YHWH" — not just "law book" — conveying covenant-constitution weight
- nātak (34:21): "poured out" for divine wrath — the liquid/libation imagery of wrath
"""

import json, pathlib

ROOT = pathlib.Path(__file__).parent.parent

def load_comm(layer, book):
    p = ROOT / 'data' / 'commentary' / layer / f'{book}.json'
    return json.loads(p.read_text()) if p.exists() else {}

def save_comm(layer, book, data):
    p = ROOT / 'data' / 'commentary' / layer / f'{book}.json'
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, ensure_ascii=False, indent=None))
    print(f'  wrote {p.relative_to(ROOT)}')

def merge_comm(existing, new_data):
    for ch, verses in new_data.items():
        if ch not in existing:
            existing[ch] = {}
        for v, html in verses.items():
            if v not in existing[ch]:
                existing[ch][v] = html

CHRON2_ORIGINAL = {
  "32": {
    "1": "<p>&lsquo;After these faithful acts (<em>ʾaḥărê haddĕḇārîm wĕhāʾĕmet hāʾēlleh</em>), Sennacherib king of Assyria came.&rsquo; The Chronicler&rsquo;s opening formula is deliberate: <em>ʾaḥărê</em> (after) + the list of Hezekiah&rsquo;s temple reforms in chs. 29&ndash;31 signals that the trial follows the faithfulness, not precedes it. <em>hāʾĕmet</em> (truth, faithfulness) as an abstract noun qualifying &lsquo;these acts&rsquo; is unusual &mdash; the phrase essentially means &lsquo;these acts of faithfulness.&rsquo; The Chronicler&rsquo;s theology of testing: YHWH permits the Assyrian threat precisely as a sequel to a period of covenant fidelity, not as punishment for sin.</p>",
    "2": "<p><em>wayyarʾ ḥizkîyāhû kî bāʾ</em> &mdash; &lsquo;Hezekiah saw that Sennacherib had come&rsquo; (<em>rāʾāh</em> + infinitive construct: he saw that Sennacherib had come, i.e., his coming was a visible fait accompli). <em>ûpānāyw lamillḥāmāh ʿal-yĕrûšālāim</em> &mdash; &lsquo;and his face was toward war against Jerusalem.&rsquo; The expression <em>pānāyw ʿal</em> (his face toward) is the directional-intention idiom: the military threat is resolved and directed, not ambiguous. Hezekiah&rsquo;s response is immediate strategic action rather than panic.</p>",
    "3": "<p><em>wayyiwwāʿaṣ ʿim-śārāyw</em> &mdash; &lsquo;he took counsel with his officers.&rsquo; The Niphal of <em>yāʿaṣ</em> (to counsel, advise) in this reflexive sense means &lsquo;he consulted together with.&rsquo; The subject of the counsel is <em>laʾsēṭōm ʾet-mêyê hammayĕnôt</em> = to stop the waters of the springs outside the city. The practical military logic: deny the invading army its water supply while securing Jerusalem&rsquo;s own. The &lsquo;mighty men&rsquo; (<em>gibbōrêhā</em>) are the technical term for the standing military force, not a general word for &lsquo;people.&rsquo;</p>",
    "4": "<p><em>wayyiqqāhᵃlû ʿam-rāb</em> &mdash; &lsquo;a large assembly gathered.&rsquo; <em>qāhal</em> (assembly, congregation) carries the covenant-assembly overtone of Sinai; its use here for a military/civic muster gives the water-blocking operation a quasi-communal significance. The purpose: <em>lāsĕtōm ʾet-kol-hammayĕnôt</em> = to stop all the springs (<em>maʿyānôt</em> + <em>naḥal</em> = springs and brooks/streams). The <em>naḥal</em> (seasonal watercourse) running through the land is specifically identified as the water they wished to deny the Assyrian kings, framing it as a denial-of-resources strategy.</p>",
    "5": "<p><em>wayyithazzēq</em> &mdash; &lsquo;he strengthened himself&rsquo; (Hithpael of <em>ḥāzaq</em>, reflexive). The Hithpael indicates Hezekiah&rsquo;s active self-strengthening: he built up the wall (<em>wayyiḇen ʾet-kol-hahōmāh</em>) that was broken down, raised towers (<em>hammigdālôt</em>), built another wall outside, reinforced the Millo (<em>wayyḥazzēq ʾet-hammillōʾ</em>), and made weapons and shields. The catalog of five building/armament actions shows systematic defense preparation. <em>millōʾ</em> (fill, the Millo) = the stone terrace/fill structure supporting the Davidic city from the time of David (2 Sam 5:9).</p>",
    "6": "<p><em>wayyittēn śārê milḥāmôt ʿal-hāʿām</em> &mdash; &lsquo;he appointed officers of war over the people.&rsquo; The verb <em>nātan</em> (to give, appoint) in the sense of commissioning/setting over is the appointment idiom. Hezekiah then gathered them at the broad place at the city gate (<em>bīrᵉḥôḇ šaʿar hāʿîr</em>) and spoke to their heart (<em>wayyḏabbēr ʿal-libbām</em>) = addressed them encouragingly. The <em>ʿal-lēḇ</em> idiom (speak to the heart) is intimate and reassuring speech &mdash; used by Joseph comforting his brothers (Gen 50:21), Boaz with Ruth (Ruth 2:13), and the suffering servant in Isa 40:2.</p>",
    "7": "<p><strong>ḥizqû wĕʾimṣû</strong> &mdash; &lsquo;Be strong and courageous!&rsquo; The combined imperative formula is the classic Deuteronomic charge: YHWH uses this exact phrase when commissioning Joshua (Josh 1:6, 7, 9) and David charges Solomon with it (1 Chr 22:13; 28:20). <em>ʾāmaṣ</em> (Qal imperative: be courageous, firm) and <em>ḥāzaq</em> (be strong) form a fixed pair. <em>ʾal-tîrĕʾû wĕʾal-tēḥattû</em> = &lsquo;do not fear and do not be dismayed/shattered&rsquo; &mdash; <em>ḥātat</em> (Niphal: to be shattered, broken, terrified) is a stronger term than general fear; it denotes being broken by terror. The charge draws on the conquest and temple-building traditions simultaneously.</p>",
    "8": "<p><strong>ʿimmô zĕrôaʿ bāśār wĕʿimmānû YHWH ʾĕlōhênû</strong> &mdash; &lsquo;With him is an arm of flesh, but with us is YHWH our God.&rsquo; The antithesis <em>bāśār</em> (flesh) vs. <em>YHWH ʾĕlōhênû</em> (YHWH our God) is one of the sharpest formulations of the Chronicler&rsquo;s theology. <em>zĕrôaʿ bāśār</em> (arm of flesh) echoes the Jeremiah/Isaiah idiom: Jer 17:5 curses the one who &lsquo;makes flesh his arm (<em>śām bāśār zĕrōʿô</em>).&rsquo; The Chronicler&rsquo;s speech has Hezekiah anticipate prophetic vocabulary, framing the Assyrian military force as categorically weak. <em>wayyissāmᵉḵû hāʿām</em> = &lsquo;the people took courage/leaned on the words.&rsquo; <em>sāmaḵ</em> (to lean, support, uphold) appears in Ps 3:5; 37:24; 54:4 as a trust-verb.</p>",
    "9": "<p>Sennacherib sends his servants to Jerusalem while he was at Lachish (<em>wĕhûʾ ʿal-lāḵîš</em>). The geographic specificity is important: Lachish was the greatest military siege operation of the period (confirmed by the Lachish reliefs at Nineveh and the Lachish letters). Hezekiah&rsquo;s refusal to capitulate forces Sennacherib to operate against Jerusalem by proxy while still besieging Lachish. The servants carry a message (<em>ʾal-yĕhûḏāh wĕʿal-kol-yôšĕḇê yĕrûšālayim</em>) to Judah and to all inhabitants of Jerusalem.</p>",
    "10": "<p><em>ʿal-meh ʾattem bōṭĕḥîm</em> &mdash; &lsquo;On what are you relying?&rsquo; The <em>bāṭaḥ</em> root (to trust, rely, be confident) is the key trust-vocabulary of the Psalms (Ps 4:5; 9:10; 21:7). Sennacherib&rsquo;s taunt deploys the language of faith against itself: he mocks Judah&rsquo;s &lsquo;confidence&rsquo; by asserting it is misplaced. The question is phrased as an aggressive interrogative: <em>ʿal-meh</em> (on what?) implies &lsquo;there is nothing.&rsquo;</p>",
    "11": "<p><em>hălōʾ ḥizkîyāhû massît ʾetḵem</em> &mdash; &lsquo;Is not Hezekiah misleading you?&rsquo; The Hiphil <em>sût</em> (to entice, mislead) is the same word used for satanic incitement (1 Chr 21:1) and Ahab&rsquo;s false prophets (2 Chr 18:2). Sennacherib frames Hezekiah as a deceiver. The argument: &lsquo;YHWH our God will deliver us from the hand of the king of Assyria&rsquo; — if Hezekiah says this, Sennacherib implies, he is lying. The taunt assumes YHWH cannot deliver, which the Chronicler will refute by narrative outcome.</p>",
    "12": "<p><em>hălōʾ-hûʾ ḥizkîyāhû hēsîr ʾet-bāmōtāyw wĕʾet-mizbĕḥōtāyw</em> &mdash; &lsquo;Has not Hezekiah himself removed his high places and altars?&rsquo; Sennacherib deploys Hezekiah&rsquo;s reform against him: the very centralization of worship at Jerusalem that the Chronicler presents as faithfulness, the Assyrian reads as having offended the Judahite deity by eliminating the regional shrines. The argument rests on a misunderstanding (or deliberate misrepresentation) of Yahwistic worship, but it is rhetorically sophisticated: Hezekiah has reduced YHWH&rsquo;s cultic footprint; maybe YHWH is now weak or angry.</p>",
    "13": "<p><em>hᵃlōʾ tēḏĕʿû meh ʿāśîtî ʾănî wăʾăḇôtay lĕkol-ʿammê hāʾărāṣôt</em> &mdash; &lsquo;Do you not know what I and my fathers have done to all the peoples of the lands?&rsquo; The historical-precedent argument: Sennacherib appeals to the documented track record of Assyrian conquest. <em>ʿāśāh</em> (to do) applied to military conquest summarizes the fall of nations. The rhetorical question form (<em>hᵃlōʾ</em>) expects the answer &lsquo;yes, you know&rsquo; — Assyrian military reputation was used deliberately as a weapon of psychological terror.</p>",
    "14": "<p><em>mî bĕkol-ʾĕlōhê haggôyim hāʾēlleh ʾăšer-hēḥĕrîmû ʾăḇôtay</em> &mdash; &lsquo;Who among all the gods of those nations that my fathers devoted to destruction...?&rsquo; <em>ḥāram</em> (Hiphil: to devote to destruction/ban) is the holy-war vocabulary &mdash; the same term for Israel&rsquo;s warfare against Canaan (Deut 7:2; Josh 6:17). Sennacherib ironically uses Israel&rsquo;s own warfare terminology to describe Assyrian conquest: he has &lsquo;devoted to destruction&rsquo; the nations and their gods. The rhetorical claim: no god (<em>kol-ʾĕlōhê</em>) could deliver from his hand; why would YHWH be different?</p>",
    "15": "<p><em>wĕʿattāh ʾal-yassî ʾetḵem ḥizkîyāhû wĕʾal-yaddîʾ ʾetḵem kāzōʾt</em> &mdash; &lsquo;And now do not let Hezekiah deceive you or mislead you like this.&rsquo; The <em>Hiphil nassāh</em> (entice, deceive) and <em>yaddîʾ</em> (from the Hiphil of <em>dāʾāh</em> or possibly <em>yiddaʿ</em>: make know/mislead) emphasize deception. The assertion follows: <em>kî lōʾ-yûkal kol-ʾĕlôah kol-gôy ûmamlāḵāh lĕhaṣṣîl ʿammô miyyāḏî</em> = &lsquo;for no god of any nation or kingdom has been able to deliver his people from my hand.&rsquo; The universal claim — <em>kol-ʾĕlôah</em>, any god — sets up the narrative refutation.</p>",
    "16": "<p>Sennacherib&rsquo;s servants continued to speak against YHWH God and against Hezekiah his servant. The addition <em>ʿaḇdô</em> (his servant) to Hezekiah&rsquo;s description is theologically pointed: Hezekiah is YHWH&rsquo;s <em>ʿeḇed</em> (servant), the same royal-Davidic title. Blaspheming Hezekiah as servant is an indirect attack on YHWH himself.</p>",
    "17": "<p><em>wĕsēper</em> &mdash; and a letter (<em>sēper</em>). The written dispatch (sēper = document, book, letter) from Sennacherib amplifies the spoken threat. The content is described as <em>lĕgaddēp ʿal-YHWH ʾĕlōhê yiśrāʾēl</em> = &lsquo;to blaspheme/reproach against YHWH God of Israel.&rsquo; <em>gāḏap</em> (to reproach, blaspheme) appears in Num 15:30 for the high-handed sinner and Ps 44:16 for divine reproach. The parallel with Isa 36-37 (Hezekiah lays the letter before YHWH in the temple) suggests the letter was a formal diplomatic-religious challenge.</p>",
    "18": "<p><em>wayyiqrĕʾû bĕqôl gādôl yĕhûdît</em> &mdash; &lsquo;They cried with a loud voice in the Judean [language].&rsquo; <em>yĕhûdît</em> (Judahite/Hebrew, the language of Judah) is the term used in 2 Kgs 18:26, 28 to distinguish the vernacular from Aramaic. The political-psychological strategy: the Assyrian negotiators deliberately chose the people&rsquo;s own language to undermine civilian morale, bypassing the official negotiators. The phrase <em>lĕharʾît ûlĕbahᵃlām</em> = &lsquo;to frighten and terrify them&rsquo; — <em>yārēʾ</em> (to fear) and <em>bāhal</em> (to be disturbed, terrified) &mdash; confirms that psychological warfare was the explicit goal.</p>",
    "19": "<p><em>wayyḏabbĕrû ʾel-ʾĕlōhê yĕrûšālayim</em> &mdash; &lsquo;They spoke against the God of Jerusalem&rsquo; as if YHWH were like the gods of the peoples of the earth (<em>kĕʾĕlōhê ʿammê hāʾāreṣ</em>) — the work of human hands (<em>maʿăśēh yĕḏê hāʾāḏām</em>). The equation of YHWH with handmade gods is the core blasphemy. The Chronicler&rsquo;s formulation is precise: the Assyrians argued by category error — grouping YHWH with manufactured gods. The polemic against &lsquo;works of human hands&rsquo; appears throughout the prophets (Isa 2:8; Jer 10:3-5; Ps 115:4-7) as the definitional weakness of idols.</p>",
    "20": "<p><em>wayyitpallēl ḥizkîyāhû hammelek ûyĕšaʿyāhû ben-ʾāmôṣ hannāḇîʾ ʿal-zōʾt wayyizʿaqû haššāmāyim</em> &mdash; &lsquo;King Hezekiah and Isaiah son of Amoz the prophet prayed about this and cried to heaven.&rsquo; The dual subject prayer (king + prophet) is unique in the historical books. <em>zāʿaq haššāmāyim</em> (cried to the heavens) is the direct address of prayer; the spatial directional (<em>haššāmāyim</em> = the heavens) frames YHWH as enthroned above, accessible by upward-directed speech. The combination of <em>hitpallēl</em> (formal intercessory prayer) and <em>zāʿaq</em> (urgent cry) signals both structured petition and emotional urgency.</p>",
    "21": "<p><em>wayyi$laḥ YHWH malʾāk</em> &mdash; &lsquo;YHWH sent an angel.&rsquo; The identity of the agent is minimally specified: simply <em>malʾāk</em> (messenger/angel). The Chronicler does not cite the 185,000 figure from 2 Kgs 19:35 but describes the outcome as: <em>wayyaṣmēt kol-gibbôr ḥayil wĕnāgîḏ wĕśār</em> = &lsquo;it destroyed every mighty warrior, leader, and officer.&rsquo; The three-fold military hierarchy (<em>gibbôr / nāgîḏ / śar</em>) encompasses the entire command structure. <em>wayyāšāḇ ḇōšet pānîm lĕʾarṣô</em> = Sennacherib &lsquo;returned in shame of face to his land&rsquo; — <em>bōšet pānîm</em> (shame of face) is public disgrace that reverses the honor of conquest.</p>",
    "22": "<p><em>wayyôšaʿ YHWH ʾet-ḥizkîyāhû wĕʾēt yôšĕḇê yĕrûšālayim miyyaḏ sannḥērîḇ melek ʾaššûr ûmiyyaḏ-kōl</em> &mdash; &lsquo;YHWH saved Hezekiah and the inhabitants of Jerusalem from the hand of Sennacherib.&rsquo; The Hiphil <em>wāyôšaʿ</em> (he saved, from <em>yāšaʿ</em>) is the Exodus/salvation vocabulary applied to the deliverance from Assyria. <em>wayyĕnahᵃlēm miSSāḇîḇ</em> = &lsquo;he gave them rest on every side&rsquo; (<em>nāḥāl</em> in Piel: to guide, give inheritance/rest; <em>miSSāḇîḇ</em> = from all around). The rest-on-every-side formula recalls the Davidic promise (1 Chr 22:9) and Deuteronomic blessing (Deut 12:10).</p>",
    "23": "<p><em>wĕraббîm mĕḇîʾîm minḥāh laYHWH lîrûšālāyim</em> &mdash; &lsquo;Many brought gifts to YHWH in Jerusalem.&rsquo; The tribute-bringing in the aftermath of deliverance echoes the Solomonic scenario (ch. 9): nations coming to Jerusalem with gifts. The nations (<em>wĕladōnîm laḵol-haggôyim</em>) who see the deliverance bring tribute and valuable gifts to Hezekiah. The reward of international recognition is the Chronicler&rsquo;s indicator that YHWH&rsquo;s vindication had global visibility.</p>",
    "24": "<p><em>bāyyāmîm hāhēm ḥālāh ḥizkîyāhû ʿaḏ-lāmût</em> &mdash; &lsquo;In those days Hezekiah was sick to the point of death.&rsquo; The timing &lsquo;in those days&rsquo; is the same phrase used in 2 Kgs 20:1 and Isa 38:1, placing the illness in the same period as the Sennacherib crisis. <em>wayyitpallēl ʾel-YHWH</em> = he prayed to YHWH. <em>wayyōʾmer lô wĕʾôt nātan lô</em> = &lsquo;he spoke to him and gave him a sign (<em>ʾôt</em>).&rsquo; The sign (the shadow going back on the sundial) is referenced but not described; the Chronicler presupposes reader knowledge from the Isaiah 38 parallel. The <em>ʾôt</em> (sign) as divine authentication of prophetic promise is standard (Exod 4:8-9; Isa 7:11-14).</p>",
    "25": "<p><em>kî-hē ḵiḇ libbô wayyigbah libbô</em> &mdash; &lsquo;but Hezekiah&rsquo;s heart was proud.&rsquo; The idiom <em>gāḇah lēḇ</em> (to lift/elevate the heart = pride) is exactly the same formula used of Uzziah in 26:16. The term <em>kî-hē ḵiḇ</em> (reciprocal: &lsquo;not corresponding to the benefit done to him&rsquo;) signals the ingratitude framework: Hezekiah failed to respond in kind (<em>kĕgāmlô</em> = according to/corresponding to the good done to him). The wrath (<em>qeṣep</em>) came upon him and upon Judah and Jerusalem. This brief noticing of pride — absent from 2 Kings — is characteristically Chronicler: even the best kings are susceptible to the prosperity-to-pride pattern.</p>",
    "26": "<p><em>wayyiḵkānēʿ ḥizkîyāhû bĕgōḇah libbô</em> &mdash; &lsquo;Hezekiah humbled himself in the pride of his heart.&rsquo; <em>kānaʿ</em> (Niphal: to be humbled, brought low) is the Chronicler&rsquo;s key repentance verb (cf. 12:6-7, 12; 33:12, 19, 23; 34:27; 36:12). The preposition <em>bĕgōḇah libbô</em> (in/because of the height of his heart) makes the object of the humbling explicit: he humbled himself precisely in the thing that was exalted. <em>wattiškoḵ ʿālāyw qeṣep YHWH</em> = &lsquo;the wrath of YHWH did not come upon him in the days of Hezekiah.&rsquo; The averted judgment through humbling is the Chronicler&rsquo;s reward of repentance.</p>",
    "27": "<p>The description of Hezekiah&rsquo;s wealth and glory (<em>kāḇôḏ ʿōšer</em>) follows the pattern of Solomon&rsquo;s wealth catalog (ch. 9). <em>ʿāśāh-lô ʾōṣĕrôt</em> = he made storehouses (<em>ʾôṣār</em>) for silver, gold, precious stones, spices, shields, and all desirable things. The list mimics the Solomonic tribute inventory, implying that Hezekiah&rsquo;s reign represents a second peak of covenant prosperity after the Solomonic golden age.</p>",
    "28": "<p><em>ûmiškenôt lĕtĕḇûʾat dāgān wĕtîrôš wĕyiṣhār</em> &mdash; storehouses for grain, wine, and oil. The agricultural triad (grain, wine, oil) is the Deuteronomic prosperity formula (Deut 7:13; 11:14; 14:23), the covenant blessings of the land. Their appearance in Hezekiah&rsquo;s catalog signals covenant-blessing fulfillment. <em>rĕpātôt lĕkol-bĕhēmōt</em> = stalls for all kinds of livestock; <em>wĕʿadrôt laṣṣōʾn</em> = sheepfolds. The specificity signals real administrative infrastructure, not just rhetorical prosperity.</p>",
    "29": "<p><em>ûʿārîm bānāh lô</em> &mdash; and cities he built for himself. The building of cities (<em>ʿārîm</em>) is the administrative-expansion indicator of a successful reign (cf. Solomon in 2 Chr 8:4-6; Jehoshaphat in 2 Chr 17:12). <em>ûmikneh-ṣōʾn ûḇāqār lārōḇ</em> = herds of sheep and cattle in abundance. <em>kî nātan-lô ʾĕlōhîm rĕkûš rāḇ mĕʾōḏ</em> = &lsquo;for God gave him very great possessions.&rsquo; The Chronicler&rsquo;s closing attribution: all the wealth is divine gift (<em>nātan</em>), not human accumulation.</p>",
    "30": "<p><em>wayyiśkōr ḥizkîyāhû ʾet-môṣāʾ-mêyê gîḥôn haʿelyônāh</em> &mdash; &lsquo;Hezekiah blocked the upper outlet of the Gihon spring.&rsquo; This verse refers to the Siloam tunnel (Hezekiah&rsquo;s tunnel), one of the best-confirmed archaeological remains of the Israelite monarchy period. The 533-meter tunnel, discovered in 1880 with its inscription intact, was cut through bedrock to divert the Gihon spring inside Jerusalem&rsquo;s walls. <em>wayyayyᵉšārēm lĕmaṭṭāh māʿǎrab</em> = &lsquo;and directed them straight down to the west side of the city of David.&rsquo; The Chronicler summarizes the hydrological engineering in one verse; 2 Kgs 20:20 also references it without description. <em>wayyaṣlaḥ ḥizkîyāhû</em> = Hezekiah prospered.</p>",
    "31": "<p><em>ûḇên haSSîrîm hammalʾāḵîm śarê ḇāḇel</em> &mdash; &lsquo;in the matter of the envoys of the princes of Babylon.&rsquo; The Babylonian diplomatic mission (also in 2 Kgs 20:12-15 and Isa 39) is noted with a theological comment absent from Kings: <em>ʿăzāḇô hāʾĕlōhîm lĕnassōtô lāḏaʿat kol-bĕlibbô</em> = &lsquo;God left him to himself in order to test him, to know all that was in his heart.&rsquo; <em>nāsāh</em> (to test, prove) is the divine testing verb of Gen 22:1 and Exod 15:25; 16:4; 20:20. The Chronicler&rsquo;s editorial comment is unique: YHWH deliberately withdrew support to reveal what was truly in Hezekiah&rsquo;s heart. This explains his pride (v25): the Babylonian embassy was the test-context.</p>",
    "32": "<p><em>wĕyeter diḇrê ḥizkîyāhû waḥăsāḏāyw hinnām kĕtûḇîm</em> &mdash; &lsquo;The rest of the acts of Hezekiah and his good deeds, they are written.&rsquo; <em>ḥăsāḏāyw</em> (his acts of faithfulness/loyal love) &mdash; <em>ḥeseḏ</em> applied to a king&rsquo;s acts is the covenant-loyalty vocabulary. The Chronicler cites the vision of Isaiah son of Amoz the prophet (<em>ḥăzôn yĕšaʿyāhû ben-ʾāmôṣ hannāḇîʾ</em>) in the book of the kings of Judah and Israel as the primary source. Citing a prophetic vision (<em>ḥāzôn</em>) as the historical source signals that Hezekiah&rsquo;s reign was prophetically witnessed and interpreted, not merely chronicled.</p>",
    "33": "<p><em>wayyiškab ḥizkîyāhû ʿim-ʾăḇôtāyw</em> &mdash; &lsquo;Hezekiah slept with his fathers.&rsquo; The standard regnal death formula. <em>wayyiqbĕrûhû bĕmaʿălēh qiḇrê ḇĕnê-ḏāwîḏ</em> = buried in the ascent of the tombs of the sons of David. The distinction from &lsquo;in the city of David&rsquo; (the more honorific burial ground) is preserved; yet the Chronicler adds <em>wĕḵāḇôḏ nātĕnû-lô ḇĕmôtô kol-yĕhûḏāh wĕyôšĕḇê yĕrûšālāyim</em> = &lsquo;all Judah and inhabitants of Jerusalem honored him at his death.&rsquo; The community&rsquo;s honor at burial (<em>kāḇôḏ</em>) is the social validation of a good reign.</p>"
  },
  "33": {
    "1": "<p><em>ben-šĕtêm ʿeśreh šānāh mĕnaššeh bĕmolkô</em> &mdash; &lsquo;Manasseh was twelve years old when he became king.&rsquo; Born during Hezekiah&rsquo;s fifteen-year extension after his illness (32:24-26), Manasseh is the product of the reprieve. His fifty-five year reign (<em>ḥămiššîm waḥāmēš šānāh</em>) is the longest of any Judahite king, exceeding Solomon (forty years) and David (forty years). The length of the reign contrasts sharply with its theological content, creating the Chronicler&rsquo;s most sustained portrait of apostasy-then-restoration.</p>",
    "2": "<p><em>wayyaʿaś hārāʿ bĕʿênê YHWH</em> &mdash; &lsquo;He did evil in the eyes of YHWH.&rsquo; The standard apostasy formula. <em>kĕtôʿăḇôt haggôyim</em> = &lsquo;according to the abominations of the nations.&rsquo; <em>tôʿēḇāh</em> (abomination) is the Deuteronomic term for practices that are fundamentally incompatible with YHWH&rsquo;s holiness (Deut 7:25-26; 12:31; 18:9-12). The Chronicler specifies which nations YHWH drove out before Israel &mdash; their practices are precisely what Israel was prohibited from imitating.</p>",
    "3": "<p><em>wayyāšāḇ wayyiḇen ʾet-habbāmôt ʾăšer nittaṣ ḥizkîyāhû ʾāḇîw</em> &mdash; &lsquo;He rebuilt the high places that his father Hezekiah had demolished.&rsquo; The reversal verb <em>wayyāšāḇ</em> (returned/went back; Qal of <em>šûḇ</em>) applied to cult practice signals apostasy as retrogression. The father&rsquo;s reform work (<em>nittaṣ</em>, Niphal of <em>nāṭaš</em>: was pulled down/demolished) is undone by the son. <em>wayyiḵrōṯ mizbĕḥôt labbe bĕ ālîm</em> = set up altars for the Baals; <em>wayyaʿaś ʾăšērôt</em> = made Asherah poles. The Baals and Asherah represent the primary Canaanite fertility cult complex.</p>",
    "4": "<p><em>wayyiḇen mizbĕḥôt bĕbêt YHWH</em> &mdash; &lsquo;He built altars in the house of YHWH.&rsquo; The desecration of the temple is the central apostasy: foreign altars installed in YHWH&rsquo;s own house. The Chronicler notes the divine counterpoint: <em>ʾăšer ʾāmar YHWH bîrûšālayim yihyeh šĕmî lĕʿôlām</em> = &lsquo;of which YHWH had said: In Jerusalem my name shall be forever.&rsquo; The &lsquo;name-dwelling&rsquo; theology (Deuteronomy&rsquo;s <em>šēm</em> formula) is invoked precisely here to show the magnitude of the desecration: the permanently named sanctuary is being contaminated.</p>",
    "5": "<p><em>mizbĕḥôt lĕkol-ṣĕḇāʾ haššāmayim</em> &mdash; altars for &lsquo;all the host of heaven.&rsquo; <em>ṣĕḇāʾ haššāmayim</em> (host of heaven) = the stellar/planetary deities of Mesopotamian astral religion. Altars to these were placed in both courts of the temple (<em>bišĕtê ḥaṣrôt bêt-YHWH</em>). Astral worship was associated with Assyrian influence (2 Kgs 21:3-5 parallels this) and represents the cultural-imperial pressure of Assyrian hegemony on Judahite cult. Deut 17:3 explicitly prohibits worship of <em>ṣĕḇāʾ haššāmayim</em>.</p>",
    "6": "<p><em>wĕhûʾ heʿbîr ʾet-bānāyw bāʾēš bĕgêʾ ben-hinnōm</em> &mdash; &lsquo;He passed his sons through fire in the valley of Ben Hinnom.&rsquo; Child sacrifice at the Hinnom valley (the historical site of later &lsquo;Gehenna&rsquo;) is repeated from ch. 28:3 (Ahaz). The catalog of occult practices that follows uses the full technical vocabulary of Deut 18:10-14: <em>ʿônēn</em> (one who observes times/divines, Piel of <em>ʿānan</em>), <em>niḥēš</em> (practiced divination by omens, Piel of <em>nāḥaš</em>), <em>kēšep</em> (used sorcery, from <em>kaššāp</em>), <em>ʿāśāh ʾôḇ wĕyiddĕʿōnî</em> (dealt with mediums and spiritists). Deuteronomy lists these as the defining practices of the nations driven out before Israel; Manasseh reinstates all of them.</p>",
    "7": "<p><em>wayyāśem ʾet-pesel hassĕmel ʾăšer ʿāśāh bĕbêt hāʾĕlōhîm</em> &mdash; &lsquo;He set the carved image of the idol that he made in the house of God.&rsquo; <em>pesel</em> (carved image) is the idol-vocabulary of the Second Commandment (Exod 20:4). <em>hassĕmel</em> = &lsquo;the idol/likeness&rsquo; (a rare term, appearing also in Ezek 8:3, 5 for the detestable image in the temple vision). YHWH had said of this temple (<em>ʾel-šĕlōmōh</em>): &lsquo;In this house and in Jerusalem... I will put my name forever.&rsquo; Installing a carved idol in the named sanctuary is the direct negation of everything the Solomonic temple represents.</p>",
    "8": "<p><em>wĕlōʾ ʾôsîp lĕhāšîm ʾet-regel yiśrāʾēl</em> &mdash; &lsquo;I will no more cause the foot of Israel to move.&rsquo; The conditional promise embedded in YHWH&rsquo;s word about the temple: Israel&rsquo;s stability (<em>rāgal</em> = foot/footing) depends on keeping the Torah (<em>wĕšāmĕrû lāʿăśôt ʾēt kol-ʾăšer ṣiwwîtî</em>). <em>ʾal-mâh</em> + the giving of the Torah = the conditional structure of the Davidic-Solomonic covenant. The negative formulation (&lsquo;I will not again move them&rsquo;) makes the implicit threat explicit: violate these conditions and the foot <em>will</em> move &mdash; which is exactly what happens in exile.</p>",
    "9": "<p><em>wayyaṭʿeh mĕnaššeh ʾet-yĕhûḏāh wĕʾet-yôšĕḇê yĕrûšālayim</em> &mdash; &lsquo;Manasseh led Judah and the inhabitants of Jerusalem astray.&rsquo; <em>tāʿāh</em> (Hiphil: to cause to wander, lead astray) is the apostasy-leadership verb: what the king does, the nation does. <em>lāʿăśôt rāʿ min-haggôyim</em> = &lsquo;to do more evil than the nations.&rsquo; The comparative <em>min</em> (more than) creates a superlative of apostasy: Manasseh exceeded the Canaanites whom Israel displaced. This is the strongest negative verdict in Chronicles; the parallel in 2 Kgs 21:9 also uses the comparative.</p>",
    "10": "<p><em>wayyḏabbēr YHWH ʾel-mĕnaššeh wĕʾel-ʿammô wĕlōʾ hiqqîšîbû</em> &mdash; &lsquo;YHWH spoke to Manasseh and his people, but they paid no attention.&rsquo; <em>qāšaḇ</em> (Hiphil: to give attention, listen carefully) in the negative: <em>wĕlōʾ hiqqîšîbû</em> = they did not attend. The image is of someone speaking clearly and directly while the hearer refuses to orient. The Chronicler does not specify the form of YHWH&rsquo;s speech (prophet? Scripture?), leaving it as a general divine address that was deliberately ignored.</p>",
    "11": "<p><em>wayyāḇēʾ YHWH ʿălêhem ʾet-śārê ṣĕḇāʾ melek ʾaššûr</em> &mdash; &lsquo;YHWH brought against them the commanders of the army of the king of Assyria.&rsquo; The divine subject of Assyrian military action is the Chronicler&rsquo;s key framing: the Assyrians are YHWH&rsquo;s instrument, not autonomous aggressors. <em>wayyilkĕḏû ʾet-mĕnaššeh baḥôḥîm</em> = &lsquo;they captured Manasseh with hooks.&rsquo; <em>ḥôaḥ</em> (hook, thorn) used for leading captives is confirmed by Assyrian reliefs showing captives led by hooks through their lips or nose. <em>wayyeʾasrûhû bĕnaḥoštayim</em> = bound him with bronze fetters (<em>naḥôšet</em> = bronze/copper; dual <em>naḥuštayim</em> = double-chains). <em>wayyôlîḵûhû bāḇelāh</em> = brought him to Babylon.</p>",
    "12": "<p><em>ûḵĕhāṣar lô ḥillāh ʾet-pĕnê YHWH ʾĕlōhāyw</em> &mdash; &lsquo;When he was in distress, he entreated the face of YHWH his God.&rsquo; <em>ṣārar</em> (to be in straits, distress) in the infinitive of temporal clause: when he was pressed/confined (<em>ḵĕhāṣar lô</em>). <em>ḥālāh pānê YHWH</em> = &lsquo;he sought the face of YHWH&rsquo; (lit. &lsquo;made smooth/sick the face&rsquo; — an idiom for imploring, from the image of prostrating in need). <em>wayyiḵkānēʿ mĕʾōḏ</em> = &lsquo;he humbled himself greatly.&rsquo; The intensifier <em>mĕʾōḏ</em> (greatly, exceedingly) marks the depth of the repentance. <em>kānaʿ</em> appears here in one of its most dramatic OT applications: the worst king produces the most intense humbling.</p>",
    "13": "<p><em>wayyitpallēl ʾēlāyw wayyēʿātēr lô</em> &mdash; &lsquo;He prayed to him and he was entreated by him.&rsquo; <em>ʿātar</em> (Niphal: to be moved/entreated by prayer) is used of divine responsiveness to petition (Gen 25:21; Exod 8:30; 2 Sam 21:14). <em>wayyišmaʿ tĕḥinnātô</em> = &lsquo;he heard his supplication.&rsquo; <em>tĕḥinnāh</em> (supplication, plea for grace) is the strongest petition term, from <em>ḥānan</em> (to be gracious, show favor). The restoration is politically concrete: <em>wayyᵃšîḇēhû yĕrûšālayim lĕmalkûtô</em> = &lsquo;he restored him to Jerusalem to his kingdom.&rsquo; The Chronicler&rsquo;s unique addition concludes: <em>wayyēḏaʿ mĕnaššeh kî YHWH hûʾ hāʾĕlōhîm</em> = &lsquo;then Manasseh knew that YHWH is God.&rsquo; The goal of the exile is <em>yāḏaʿ</em> (knowledge): the worst apostasy produces the clearest confession.</p>",
    "14": "<p>After his restoration Manasseh built a second outer wall for the city of David west of the Gihon spring, through the valley, to the entrance of the Fish Gate, encircling Ophel (<em>ʾōpel</em>). The topographic specificity (Gihon spring, Fish Gate, Ophel) corresponds to archaeological identifications in the City of David. <em>wayyāgĕḇah mĕʾōḏ</em> = the wall was made very high. Military commanders (<em>śārê-ḥayil</em>) were placed in all the fortified cities.</p>",
    "15": "<p><em>wayyāsar ʾet-ʾĕlōhê hannēkār</em> &mdash; &lsquo;He removed the foreign gods.&rsquo; Manasseh&rsquo;s reform catalog: removing foreign gods, the idol from the temple, the altars he had built from the mountain of YHWH&rsquo;s house, and casting them outside the city. <em>wayyᵉkōnnēn ʾet-mizbaḥ YHWH</em> = he restored the altar of YHWH (Piel of <em>kûn</em>: to establish, restore to its proper state). The reform is the structural reverse of the apostasy catalog in vv. 3-7.</p>",
    "16": "<p><em>wayyizbaḥ ʿālāyw zibḥê šĕlāmîm ûtôḏôt</em> &mdash; &lsquo;He sacrificed on it peace offerings and thank offerings.&rsquo; <em>šelāmîm</em> (peace/fellowship offerings) and <em>tôḏôt</em> (thank offerings, plural of <em>tôḏāh</em>) represent the voluntary response sacrifices of gratitude, not obligatory atonement sacrifices. Manasseh commands Judah to serve YHWH God of Israel. The reform reaches its social dimension: from personal conviction to national command. The Chronicler notes the incomplete result: the people continued sacrificing at high places, &lsquo;only to YHWH their God&rsquo; (<em>raq lĕ-YHWH ʾĕlōhêhem rāq</em>).</p>",
    "17": "<p><em>wĕhaʿām ʿôḏ mĕzabbĕḥîm babbāmôt</em> &mdash; &lsquo;But the people still sacrificed at the high places.&rsquo; The failure of the reform to fully purge the regional shrines &mdash; even after Manasseh&rsquo;s dramatic restoration &mdash; signals the depth of syncretism&rsquo;s entrenchment. The Chronicler&rsquo;s note <em>raq lĕ-YHWH ʾĕlōhêhem</em> (only to YHWH their God) distinguishes this from outright idolatry: it is unauthorized worship of the right God, not worship of wrong gods. But the Deuteronomic theology (Deut 12:4-14) makes the location of worship as important as the object.</p>",
    "18": "<p><em>wĕyeter diḇrê mĕnaššeh ûtĕpillātô</em> &mdash; &lsquo;The rest of the acts of Manasseh and his prayer.&rsquo; The Chronicler references &lsquo;his prayer&rsquo; (<em>tĕpillātô</em>) as a source document, now recorded in the acts of the kings of Israel. An apocryphal text, <em>The Prayer of Manasseh</em>, survives in the Apocrypha and is associated with this reference, though whether it is the original prayer or a later composition inspired by this verse is disputed. The prophetic sources cited: the seers (<em>ḥōzîm</em>) who spoke to Manasseh in the name of YHWH God of Israel. <em>ḥōzeh</em> (seer) is the visionary prophetic title, distinct from the speaking prophet (<em>nāḇîʾ</em>).</p>",
    "19": "<p><em>ûtĕpillātô wayyēʿātēr lô wĕkol-ḥattāʾtô ûmaʿlô</em> &mdash; &lsquo;His prayer and how God was moved by him, and all his sin and his unfaithfulness.&rsquo; <em>ḥattāʾt</em> (sin, offense) and <em>māʿal</em> (treachery, covenant-unfaithfulness) are both cited; the comprehensive record of apostasy is noted alongside the prayer record. The Chronicler emphasizes the sites before he humbled himself (<em>lipnê hikkānĕʿô</em>) where altars were built &mdash; making the restoration forensically detailed.</p>",
    "20": "<p><em>wayyiškab mĕnaššeh ʿim-ʾăḇôtāyw</em> &mdash; &lsquo;Manasseh slept with his fathers.&rsquo; <em>wayyiqbĕrûhû bĕḇêtô</em> = buried in his house. The burial location (in his house rather than in the royal tombs) is unusual; 2 Kgs 21:18 adds &lsquo;in the garden of his house, in the garden of Uzza.&rsquo; Whether burial in a private garden rather than the royal tomb reflects his compromised legacy or simply reflects changing burial customs is uncertain.</p>",
    "21": "<p>Amon was twenty-two years old when he became king (<em>ben-ʿeśrîm ûštayim šānāh ʾāmôn bĕmolkô</em>) and reigned two years in Jerusalem (<em>ûštayim šānîm mālaḵ bîrûšālāyim</em>). The brevity of Amon&rsquo;s reign (the shortest in Judah alongside Amaziah&rsquo;s assassination) signals its catastrophic trajectory even before the content is described. The standard evaluation follows: he did evil in YHWH&rsquo;s eyes.</p>",
    "22": "<p><em>wayyizbah lĕkol-happĕsîlîm ʾăšer ʿāśāh ʾāmôn ʾāḇîw</em> &mdash; &lsquo;He sacrificed to all the carved images that his father Amon [<em>sic</em> — Manasseh] had made.&rsquo; The text may have a copying error (Amon is listed as both the king and his father); the intended referent is Manasseh. The point is: Amon restored the idols Manasseh had removed, but unlike Manasseh, Amon never humbled himself. <em>wĕlōʾ hiḵkānēʿ mippe nê YHWH</em> = &lsquo;he did not humble himself before YHWH.&rsquo; The absence of <em>kānaʿ</em> is the decisive negative.</p>",
    "23": "<p><em>kî Amon hurbāh ʾāšam</em> &mdash; &lsquo;Amon greatly increased his guilt.&rsquo; The verb <em>hirbāh</em> (Hiphil of <em>rāḇāh</em>: to multiply, increase) applied to <em>ʾāšam</em> (guilt) describes the quantitative accumulation of unfaithfulness. This is the Chronicler&rsquo;s familiar compounding-sin formula (cf. 28:22 on Ahaz). Unlike Manasseh, Amon takes the apostasy deeper without the corrective of exile or humbling.</p>",
    "24": "<p><em>wayyiqŝrû ʿālāyw ʿăḇādāyw wayyĕmîtûhû bĕḇêtô</em> &mdash; &lsquo;His servants conspired against him and killed him in his house.&rsquo; <em>qāšar</em> (to conspire, bind together) is the regicide-conspiracy verb (cf. 2 Chr 24:21 for Joash; 2 Kgs 9:14 for Jehu). The killing in his house indicates an inside plot by court officials. The motive is unspecified, but palace coups in the ancient Near East typically combined political grievances with opportunism.</p>",
    "25": "<p><em>wayyakkû ʿam-hāʾāreṣ ʾet kol-haqqōšĕrîm ʿal-ʾāmôn</em> &mdash; &lsquo;The people of the land struck down all who had conspired against Amon.&rsquo; The <em>ʿam hāʾāreṣ</em> (people of the land) is a recurring social actor in Chronicles and Kings, representing a conservative constituency that acts to restore dynastic legitimacy when it is threatened by coups. They execute the conspirators and install Josiah. <em>wayyamlîḵû ʾet-yōʾšîyāhû ḇĕnô taḥtāyw</em> = they made Josiah his son king in his place. The <em>ʿam hāʾāreṣ</em>&rsquo;s role here parallels their action after Athaliah&rsquo;s coup (2 Chr 23:13, 21): they are a check on palace illegitimacy.</p>"
  },
  "34": {
    "1": "<p><em>ben-šĕmôneh šānāh yōʾšîyāhû bĕmolkô</em> &mdash; &lsquo;Josiah was eight years old when he became king.&rsquo; The youngest king to ascend in Judah; only Joash (seven years old, 2 Chr 24:1) was younger. The implication is that his reform, beginning in his eighth regnal year (v3), was initiated when he was sixteen — a young man already seeking YHWH independently of court influence. <em>wayyimlōḵ šĕlōšîm wĕʾaḥat šānāh bîrûšālāyim</em> = thirty-one years in Jerusalem.</p>",
    "2": "<p><em>wayyaʿaś hayyāšār bĕʿênê YHWH</em> &mdash; &lsquo;He did what was right in the eyes of YHWH.&rsquo; <em>wayyēlek bĕdarkê dāwîḏ ʾāḇîw</em> = &lsquo;he walked in the ways of his father David.&rsquo; The David-standard (<em>kĕdāwîḏ</em>) is the positive benchmark for Judahite kings. The qualification <em>wĕlōʾ-sār yāmîn ûśĕmōʾl</em> = &lsquo;he did not turn aside to the right or to the left&rsquo; is the Deuteronomic obedience formula (Deut 5:32; 17:20; Josh 1:7) — complete covenantal adherence without partial deviation.</p>",
    "3": "<p><em>ûḇišnat šĕmôneh lĕmolkô ʿôḏennû naʿar hēḥēl lĕḏarôš lĕʾlōhê dāwîḏ ʾāḇîw</em> &mdash; &lsquo;In the eighth year of his reign, while he was still a youth, he began to seek the God of his father David.&rsquo; The age-structure of Josiah&rsquo;s reform is unique to Chronicles: the seeking begins at year eight (age 16); the active purge begins at year twelve (age 20); the temple repair and law-discovery at year eighteen (age 26). This progressive narrative shows a multi-decade deepening of covenant commitment, not a single event. <em>lĕḏarôš</em> (to seek) — the Chronicler&rsquo;s <em>dāraš</em> root, the fundamental seeking-YHWH vocabulary. In his twelfth year he began to cleanse (<em>ṭihēr</em>) Judah and Jerusalem from the high places.</p>",
    "4": "<p><em>wayyĕnattĕṣû lĕpānāyw mizbĕḥôt habbaʿālîm</em> &mdash; &lsquo;They tore down the altars of the Baals before him.&rsquo; The <em>wayyĕnattĕṣû</em> (Piel: tore down, demolished) describes the physical destruction of cultic infrastructure. The <em>ḥammānîm</em> (incense altars/sun pillars) that were above them (<em>ʾăšer-lĕmaʿlāh mēhem</em>) were cut down (<em>giddaʿ</em>, Piel of <em>gāḏaʿ</em>: to cut down/chop). The Asherah poles, carved idols, and cast images were broken in pieces (<em>šibbar</em>), ground up (<em>hēdaq</em>), and scattered on the graves of those who had sacrificed to them. The comprehensive destruction formula moves from architectural demolition to liturgical defilement of worshipers&rsquo; graves.</p>",
    "5": "<p><em>wĕʿaṣmôt kōhănîm śārap ʿal-mizbĕḥôtêhem</em> &mdash; &lsquo;He burned the bones of the priests on their altars.&rsquo; This deliberate defilement of cult sites by burning human remains on them is the strongest form of desacralization in the OT. The action fulfills the prophecy of the man of God at Bethel (1 Kgs 13:2: &lsquo;A son shall be born to the house of David, Josiah by name, and he shall sacrifice upon you the bones of men&rsquo;). The practice permanently defiled the altars as burial sites (corpse-impurity per Num 19:11-22). <em>wayyiṭhar ʾet-yĕhûḏāh wĕʾet-yĕrûšālāyim</em> = he cleansed/purified Judah and Jerusalem.</p>",
    "6": "<p>The reform extended beyond Judah&rsquo;s territory: in the cities of Manasseh, Ephraim, and Simeon, and as far as Naphtali. The geographic expansion of the reform into northern tribal territories is significant: Josiah&rsquo;s reform is pan-Israelite, not merely Judahite. With the Assyrian Empire weakening (Ashurbanipal died c. 631 BC; the Assyrian system was collapsing by Josiah&rsquo;s time), Josiah was able to extend territorial influence northward, reclaiming former Israelite territory. The Chronicler presents this as reform activity, not military expansion.</p>",
    "7": "<p><em>wayyĕnattēṣ ʾet-hammizbĕḥôt wĕʾet-hāʾăšērôt</em> &mdash; he demolished the altars and Asherah poles, crushed the idols to dust (<em>wayyiddaq ʾad-ʾāḇāq</em>; <em>dāqaq</em> = to pulverize, reduce to fine powder; <em>ʾāḇāq</em> = dust, powder). The same vocabulary is used of Moses grinding the golden calf (Exod 32:20; Deut 9:21). The total destruction implies complete cultic annihilation, not just removal. <em>wayyāšāḇ lîrûšālāyim</em> = he returned to Jerusalem after the northern campaign.</p>",
    "8": "<p><em>ûḇišnat šĕmôneh ʿeśreh lĕmolkô</em> &mdash; &lsquo;In the eighteenth year of his reign.&rsquo; Age twenty-six. Ten years after the purge began, Josiah now turns to the temple itself: <em>lĕṭahēr hāʾāreṣ wĕhabbayit</em> = &lsquo;to cleanse the land and the house.&rsquo; He sends Shaphan son of Azaliah, Maaseiah the governor of the city, and Joah son of Joahaz the recorder to repair the house of YHWH his God. The triad of officials (scribe, city governor, recorder) represents the full administrative apparatus. <em>Šāp̄ān</em> (the scribe) is the key figure: he will read the Torah scroll to the king.</p>",
    "9": "<p><em>wayyāḇōʾû ʾel-ḥilqîyāhû hakkōhēn haggāḏôl</em> &mdash; &lsquo;They came to Hilkiah the high priest.&rsquo; Hilkiah (<em>ḥilqîyāhû</em> = &lsquo;YHWH is my portion&rsquo;) is the high priest through whom the Torah scroll will be found. The money brought for the temple repair was collected by the Levites who kept the doors (<em>šōmĕrê hassap</em>): from Manasseh, Ephraim, the remnant of Israel, and all Judah and Benjamin, and the inhabitants of Jerusalem — the pan-Israelite collection echoes the northern reform audience of vv. 6-7.</p>",
    "10": "<p>The money was given to the workers (<em>ʿōśê hammĕlāʾḵāh</em>) who were overseeing the work in the house of YHWH. <em>wayyitnûhû ʿal-ʿōśê hammĕlāʾḵāh</em> = they gave it to the workers. The administrative chain from collected donations through temple officials to craftsmen parallels the organization of the tabernacle construction (Exod 35-38) and the first temple repair under Joash (2 Chr 24:8-12). The mechanics of temple maintenance are given full attention.</p>",
    "11": "<p><em>wayyi$ĕnû laḥārāšîm ûlaḇōnîm</em> &mdash; they gave it to the carpenters (<em>ḥārāš ʿēṣ</em>) and builders (<em>ḇōnîm</em>). Materials purchased: hewn stone (<em>ʾaḇnê māzēb</em>), timber (<em>ʿēṣîm</em>) for frameworks (<em>lĕmaqreh</em> = for beams/frameworks) and for the beams (<em>lĕhaqrôt</em>) for the buildings that the kings of Judah had let fall into ruin (<em>ʾĕšer ḥirrîḇû malkê yĕhûḏāh</em>). The repair work is presented as undoing the damage of faithless predecessors — Manasseh&rsquo;s fifty-five years included much neglect.</p>",
    "12": "<p><em>wĕhāʾănāšîm ʾōśîm beʾĕmûnāh bammĕlāʾḵāh</em> &mdash; &lsquo;The men were working faithfully.&rsquo; <em>beʾĕmûnāh</em> (in faithfulness/trustworthiness) modifies the work: it was done with integrity, not corruptly. Over them were appointed Jahath and Obadiah, Levites from the Merarites, and Zechariah and Meshullam from the Kohathites as supervisors (<em>lĕnassēaḥ</em>, the same root as the Psalm superscription <em>lĕmnaṣṣēaḥ</em>: to oversee, direct). All the Levites who were skilled with musical instruments were also appointed over the burden-bearers and directed all who worked in each specific task.</p>",
    "13": "<p>The Levitical administrative structure for the repair includes scribes (<em>sōpĕrîm</em>), officers (<em>šōṭĕrîm</em>), and gatekeepers (<em>šōʿărîm</em>). The three-fold Levitical administrative structure mirrors the temple-service organization established by David and Solomon. The Chronicler&rsquo;s interest in proper Levitical administration of the repair project reflects the theological principle that the sacred structure must be maintained by the properly designated personnel, not outsourced.</p>",
    "14": "<p><strong>wayyiṣmāʾ ḥilqîyāhû hakkōhēn ʾet-sēper tôrat YHWH bĕyaḏ-môšeh</strong> &mdash; &lsquo;Hilkiah the priest found the book of the Torah of YHWH given by Moses.&rsquo; <em>māṣāʾ</em> (to find) applies to an unexpected discovery: the scroll was not known to be there. <em>sēper tôrat YHWH bĕyaḏ-môšeh</em> = &lsquo;the book of the Torah of YHWH by the hand of Moses&rsquo; — <em>tôrāh</em> here carries the full weight of covenant-constitution, not merely a legal code. <em>bĕyaḏ-môšeh</em> (by Moses&rsquo;s hand) establishes Mosaic authorship as the scroll&rsquo;s authority claim. Whether this was the complete Pentateuch, Deuteronomy, or a significant portion is debated; the Deuteronomic parallels throughout the passage suggest Deuteronomy was central to what was found.</p>",
    "15": "<p><em>wayyaʿan ḥilqîyāhû wayyōʾmer ʾel-šāpān hassōpēr sēper hattôrāh māṣāʾtî bĕḇêt YHWH</em> &mdash; &lsquo;Hilkiah said to Shaphan the scribe: I have found the book of the Torah in the house of YHWH.&rsquo; The first-person perfect <em>māṣāʾtî</em> (I found) marks the discovery as a reportable event requiring immediate official attention. Hilkiah gives (<em>wayyittēn</em>) the book to Shaphan. The handoff from priest to scribe initiates the chain of transmission that will reach the king.</p>",
    "16": "<p><em>wayyāḇēʾ šāpān ʾet-hassēper ʾel-hammelek</em> &mdash; Shaphan brought the book to the king. First, he reports on the temple repair: the money has been turned over to the workers. Then: <em>wayyiqrāʾ ḇô šāpān lipnê hammelek</em> = Shaphan read in it before the king. The sequence (report on repair → present book → read from it) shows the discovery embedded in a routine administrative report, making its impact all the more dramatic — the sacred scroll surfacing in a bureaucratic briefing.</p>",
    "17": "<p><em>wayyittiḵû ʾet-hakkesep hanimsāʾ bĕḇêt YHWH</em> &mdash; the money found in the house of YHWH has been turned over. The financial report precedes the scroll report. The juxtaposition is typical Chronicler narrative technique: the material transaction (money, repair, craftsmen) frames the spiritual discovery (Torah scroll). The administrative credibility of the temple repair operation lends credibility to the setting in which the scroll is found.</p>",
    "18": "<p><em>wayyaggēḏ šāpān hassōpēr lammelek lēmōr sēper nātan-lî ḥilqîyāhû hakkōhēn</em> &mdash; &lsquo;Shaphan the scribe informed the king, saying: Hilkiah the priest has given me a book.&rsquo; The naming of the book (&lsquo;a book&rsquo;) rather than specifying the Torah immediately creates narrative suspense. <em>wayyiqrāʾ-ḇô šāpān lipnê hammelek</em> = &lsquo;and Shaphan read in it before the king.&rsquo; The oral reading aloud (public recitation of the Torah) is the standard form of covenant proclamation (cf. Deut 31:11; Neh 8:3; 2 Chr 17:9).</p>",
    "19": "<p><strong>wayyĕhî kišmōaʿ hammelek ʾet-diḇrê hattôrāh wayyiqraʿ ʾet-bĕgāḏāyw</strong> &mdash; &lsquo;When the king heard the words of the Torah, he tore his garments.&rsquo; <em>qāraʿ bĕgāḏîm</em> (tearing garments) is the classic grief-and-repentance gesture: Jacob at the report of Joseph&rsquo;s death (Gen 37:34), Joshua and Caleb at the bad report (Num 14:6), David at Abner&rsquo;s death (2 Sam 3:31), and Hezekiah at Sennacherib&rsquo;s letter (2 Kgs 19:1). The tearing is not merely symbolic despair but a physical enactment of covenant alarm: the king who hears the Torah and sees that it has not been kept tears himself as his people should have been torn by judgment.</p>",
    "20": "<p>Josiah commands Hilkiah and certain officials to inquire (<em>diršû ʾet-YHWH bᵃʿaḏî</em> = seek YHWH on my behalf) about the words of the book. The verb <em>dāraš</em> (to seek, inquire) returns in the royal command: the same seeking vocabulary that initiated Josiah&rsquo;s reform (v3, v8) now governs the response to the scroll. &lsquo;Concerning my behalf and the remnant in Israel and Judah&rsquo; (<em>ûḇaʿaḏ šĕʾērît bĕyiśrāʾēl ûḇîhûḏāh</em>) — the pan-Israelite scope of the inquiry reflects the pan-Israelite scope of the reform.</p>",
    "21": "<p><em>ḥămat YHWH ʾăšer-nittĕkāh ḇānû gĕḏôlāh ʾāšer lōʾ-šāmĕrû ʾăḇôtênû ʾet-dĕḇar YHWH</em> &mdash; &lsquo;The wrath of YHWH poured out on us is great, because our fathers did not keep the word of YHWH.&rsquo; <em>nātak</em> (Niphal: poured out) is the liquid-outpouring metaphor for divine wrath (Jer 42:18; Lam 2:4; 4:11 use the same idiom). The cause: <em>lōʾ-šāmĕrû ʾet-dĕḇar YHWH</em> (they did not keep the word of YHWH) and <em>lāʿăśôt kĕkol-hakkāt&ucirc;ḇ ʿal-hassēper hazzeh</em> (to do according to all that is written in this book). The scroll establishes the standard against which the generations are measured; the recognition of failure is the beginning of the seeking.</p>",
    "22": "<p><em>wayyēleḵ ḥilqîyāhû wayyirbê hammelek</em> &mdash; Hilkiah and the officials went to Huldah the prophetess (<em>ḥuldāh hannĕḇîʾāh</em>). <em>nĕḇîʾāh</em> (feminine: prophetess) is the same designation as Miriam (Exod 15:20), Deborah (Judg 4:4), and Isaiah&rsquo;s wife (Isa 8:3). She lived in Jerusalem in the Second Quarter (<em>wĕhîʾ yôšeḇet bîrûšālāyim bammišneh</em>). <em>mišneh</em> (second, Mishneh) = a district of Jerusalem, possibly the newer expansion of the city westward (Zeph 1:10 also references the Mishneh as a distinct urban area). That Josiah&rsquo;s officials consulted a woman prophet — when Jeremiah and Zephaniah were also active — indicates Huldah&rsquo;s recognized authority was not incidental.</p>",
    "23": "<p><em>wattōʾmer lāhem kōh-ʾāmar YHWH ʾĕlōhê yiśrāʾēl</em> &mdash; &lsquo;Thus says YHWH God of Israel.&rsquo; Huldah speaks the full prophetic messenger formula. The oracle is in two parts: judgment (vv24-25) and Josiah&rsquo;s reprieve (vv26-28). The two-part structure matches the classic prophetic oracle of doom with a secondary word of comfort to the inquirer.</p>",
    "24": "<p><em>hinnî mēḇîʾ rāʿāh ʿal-hammāqôm hazzeh</em> &mdash; &lsquo;Behold, I am bringing evil upon this place.&rsquo; The <em>hinnî</em> (behold me / I am about to) + Hiphil participle is the prophetic imminence formula: judgment is not future possibility but imminent divine action. <em>ʾet kol-hāʾālôt hakkĕtûḇôt ʿal-hassēper ʾăšer qārĕʾû</em> = &lsquo;all the curses written in the book that they read before the king.&rsquo; The Torah scroll becomes the forensic document: its curses (<em>ʾālôt</em>) activate against the people who have violated it.</p>",
    "25": "<p><em>taḥat ʾăšer ʿăzāḇûnî wayyĕqaṭṭĕrû lēʾlōhîm ʾăḥērîm</em> &mdash; &lsquo;Because they have forsaken me and burned incense to other gods.&rsquo; <em>ʿāzaḇ</em> (to forsake) returns as the primary apostasy verb. <em>wattikah ḥamatî bammāqôm hazzeh wĕlōʾ tiḵḇeh</em> = &lsquo;my wrath is poured/kindled against this place and will not be quenched.&rsquo; <em>tāḵāh</em> (Niphal: to be kindled, poured) + <em>lōʾ tiḵḇeh</em> (will not be quenched/extinguished) form the unquenchable-fire idiom for divine wrath (Jer 7:20; 17:27; Matt 3:12 — &lsquo;unquenchable fire&rsquo;).</p>",
    "26": "<p><em>wĕʾel-melek yĕhûḏāh haššōlēaḥ ʾetḵem</em> &mdash; &lsquo;And to the king of Judah who sent you.&rsquo; The second part of the oracle is addressed specifically to Josiah via the delegation. The formula distinguishes between the general judgment (vv24-25) and the personal word to the king (vv27-28). Huldah identifies Josiah by his actions: <em>diḇrê haSSēper ʾăšer šāmaʿtā</em> = the words of the scroll that he heard.</p>",
    "27": "<p><strong>yaʿan rāk lĕḇāḇĕḵā wattikkānēʿ mippānay</strong> &mdash; &lsquo;Because your heart was tender and you humbled yourself before me.&rsquo; <em>rāḵ</em> (soft, tender) applied to the heart (<em>lēḇ</em>) = sensitivity, receptiveness, the opposite of hard/obstinate. <em>kānaʿ</em> (Niphal: to humble oneself) appears again — the Chronicler&rsquo;s decisive repentance word. The double basis for the reprieve: tender heart + active humbling. Josiah&rsquo;s tearing his garments and weeping are the external evidence of the internal condition. <em>wattibkeh lĕpānay</em> = he wept before YHWH — tears as concrete evidence of heart-tenderness.</p>",
    "28": "<p><em>hinnĕnî ʾōsipĕḵā ʾel-ʾăḇôtêḵā</em> &mdash; &lsquo;Behold, I am gathering you to your fathers.&rsquo; The <em>hinnî</em> + Hiphil participle of <em>ʾāsap</em> (to gather): YHWH promises Josiah a peaceful death before the judgment falls. <em>wĕniʾsaptā ʾel-qiḇrôtêḵā bĕšālôm</em> = &lsquo;you will be gathered to your tomb in peace.&rsquo; The divine word of individual consolation within a word of corporate judgment is a consistent prophetic pattern (Jer 39:16-18 for Ebed-melech; Jer 45 for Baruch). The word &lsquo;in peace&rsquo; (<em>bĕšālôm</em>) is ironically tested: Josiah dies in battle at Megiddo (2 Chr 35:20-24), which the Chronicler will explain as his own disobedience.</p>",
    "29": "<p><em>wayyišlaḥ hammelek wayyeʾĕsōp ʾet kol-ziqnê yĕhûḏāh wîrûšālāyim</em> &mdash; &lsquo;The king sent and gathered all the elders of Judah and Jerusalem.&rsquo; The covenant-assembly after the prophetic oracle mirrors the pattern of David&rsquo;s assembly (1 Chr 28-29) and Solomon&rsquo;s temple dedication (2 Chr 5-7). The public covenant assembly is the proper response to the Torah&rsquo;s discovery: what is found is meant to be publicly proclaimed and responded to communally.</p>",
    "30": "<p><em>wayyaʿal hammelek bêt-YHWH</em> &mdash; &lsquo;The king went up to the house of YHWH.&rsquo; With all the men of Judah and inhabitants of Jerusalem, the priests, the Levites, and all the people from great to small (<em>haggāḏôl wĕhaqqāṭān</em>). <em>wayyiqrāʾ bĕʾoznêhem ʾet kol-diḇrê sēper habbĕrît</em> = &lsquo;he read in their hearing all the words of the book of the covenant.&rsquo; The public Torah reading (<em>qārāʾ bĕʾoznêhem</em>, reading in the ears/hearing of the people) is the formal covenant proclamation of Deut 31:11 and Neh 8:3. The scroll is now identified as <em>sēper habbĕrît</em> (the book of the covenant), linking it to the Sinai covenant document (Exod 24:7).</p>",
    "31": "<p><strong>wayyaʿămod hammelek ʾal-ʿammûḏô</strong> &mdash; &lsquo;The king stood at his pillar (<em>ʿammûḏ</em>).&rsquo; The royal pillar/column was the designated standing place for the king in the temple (2 Kgs 11:14; 23:3 parallel). Solomon stood before the altar (<em>wayya ʿămod lipnê mizbaḥ YHWH</em>, 2 Chr 6:12), but the king&rsquo;s standing at his pillar is the formal covenantal posture. <em>wayyikrot ʾet-habberît lipnê YHWH</em> = &lsquo;he made (cut) the covenant before YHWH.&rsquo; <em>kārat bĕrît</em> (to cut a covenant) is the standard covenant-making idiom throughout the OT. The elements of the covenant: to walk after YHWH, to keep his commands, testimonies, and statutes, with all heart and soul, to perform the words of the covenant written in this book.</p>",
    "32": "<p><em>wayyaʿămēḏ ʾet kol-hanimsāʾ bîrûšālāyim ûḇinyāmîn</em> &mdash; &lsquo;He made all who were present in Jerusalem and Benjamin stand [in the covenant].&rsquo; <em>wayyaʿămēḏ</em> (Hiphil of <em>ʿāmaḏ</em>: to cause to stand) applied to covenant standing: he constituted the assembly as covenant participants. The standing is both physical (they stood) and covenantal (they took their stand). <em>wayyaʿăśû yôšĕḇê yĕrûšālāyim kabbĕrît ʾĕlōhîm ʾĕlōhê ʾăḇôtêhem</em> = &lsquo;the inhabitants of Jerusalem acted according to the covenant of God of their fathers.&rsquo;</p>",
    "33": "<p><em>wayyāsar yôʾšîyāhû ʾet kol-hattôʿēḇôt mikkol-hāʾărāṣôt ʾăšer liḇnê yiśrāʾēl</em> &mdash; &lsquo;Josiah removed all the abominations (<em>tôʿēḇôt</em>) from all the territories belonging to the people of Israel.&rsquo; The pan-Israelite scope again: the removal extended across all former Israelite territory. <em>wayyaʿăḇēḏ kol-hanimsāʾ bĕyiśrāʾēl laʿăḇōḏ ʾet-YHWH ʾĕlōhêhem</em> = &lsquo;he made all who were present in Israel serve YHWH their God.&rsquo; <em>kol-yāmāyw lōʾ sārû mēʾaḥărê YHWH ʾĕlōhê yiśrāʾēl</em> = &lsquo;all his days they did not turn from following YHWH God of Israel.&rsquo; The Chronicler&rsquo;s closing assessment of Josiah&rsquo;s reform: complete during the king&rsquo;s lifetime, pan-Israelite in scope, covenant-constituting in character.</p>"
  }
}

def main():
    data = load_comm('mkt-original', '2chronicles')
    merge_comm(data, CHRON2_ORIGINAL)
    save_comm('mkt-original', '2chronicles', data)
    total = sum(len(vs) for vs in CHRON2_ORIGINAL.values())
    print(f'2chronicles mkt-original ch 32-34: wrote {total} verses')

if __name__ == '__main__':
    main()
